% Question 1
\question[3] Giải phương trình
\[
|2x-1| = x+3.
\]

\begin{solution}
Ta xét hai trường hợp dựa trên dấu của biểu thức trong dấu giá trị tuyệt đối.

\textbf{Trường hợp 1:} $2x-1 \ge 0 \Leftrightarrow x \ge \frac12$.
Khi đó $|2x-1| = 2x-1$, phương trình trở thành
\[
2x-1 = x+3 \quad\Longrightarrow\quad x = 4.
\]
Giá trị $x=4$ thỏa mãn điều kiện $x \ge \frac12$ nên nhận.

\textbf{Trường hợp 2:} $2x-1 < 0 \Leftrightarrow x < \frac12$.
Khi đó $|2x-1| = -(2x-1) = -2x+1$, phương trình trở thành
\[
-2x+1 = x+3 \quad\Longrightarrow\quad -3x = 2 \quad\Longrightarrow\quad x = -\frac23.
\]
Giá trị $x = -\frac23$ thỏa mãn điều kiện $x < \frac12$ nên nhận.

Vậy tập nghiệm của phương trình là $S = \left\{-\dfrac23;\,4\right\}$.
\end{solution}

% Question 2
\question[3] Tính giới hạn
\[
L = \lim_{x\to 2} \frac{x^3 - 8}{x^2 - 4}.
\]

\begin{solution}
Khi $x\to 2$, cả tử và mẫu đều dần tới $0$ (dạng vô định $\frac{0}{0}$).
Ta phân tích tử và mẫu thành nhân tử.

\begin{align*}
x^3 - 8 &= (x-2)(x^2 + 2x + 4),\\
x^2 - 4 &= (x-2)(x+2).
\end{align*}

Do đó, với $x\neq 2$,
\[
\frac{x^3 - 8}{x^2 - 4}
= \frac{(x-2)(x^2+2x+4)}{(x-2)(x+2)}
= \frac{x^2 + 2x + 4}{x+2}.
\]

Áp dụng quy tắc giới hạn của hàm phân thức xác định tại điểm $x=2$, ta có
\[
L = \lim_{x\to 2} \frac{x^2 + 2x + 4}{x+2}
   = \frac{2^2 + 2\cdot 2 + 4}{2+2}
   = \frac{4 + 4 + 4}{4}
   = \frac{12}{4} = 3.
\]

Vậy $L = 3$.
\end{solution}

% Question 3 with TikZ figure
\question[4] Cho hình chóp $S.ABC$ có đáy $ABC$ là tam giác vuông cân tại $B$, $AB = a$, cạnh bên $SA$ vuông góc với mặt phẳng đáy và $SA = a\sqrt{2}$.

\begin{parts}
\part[2] Tính thể tích khối chóp $S.ABC$ theo $a$.
\part[2] Tính khoảng cách từ điểm $A$ đến mặt phẳng $(SBC)$.
\end{parts}

\begin{solution}
(Tham khảo hình vẽ minh họa.)

\begin{center}
\begin{tikzpicture}[scale=1.2,
    x={(0.7cm,0.4cm)},
    y={(0cm,1cm)},
    z={(-0.7cm,0.4cm)}]
% Coordinates
\coordinate (A) at (0,0,0);
\coordinate (B) at (2,0,0);
\coordinate (C) at (2,2,0);
\coordinate (S) at (0,0,3.5);
% Draw edges
\draw[thick] (A) -- (B) node[midway,below] {$a$};
\draw[thick] (A) -- (C);
\draw[thick] (B) -- (C) node[midway,right] {$a$};
\draw[thick] (S) -- (A) node[midway,left] {$a\sqrt{2}$};
\draw[thick] (S) -- (B);
\draw[thick] (S) -- (C);
\draw[dashed] (A) -- (C);
% Nodes
\node[left] at (A) {$A$};
\node[right] at (B) {$B$};
\node[right] at (C) {$C$};
\node[above] at (S) {$S$};
% Right angle at B
\draw (B) -- ++(-0.3,0,0) -- ++(0,0.3,0) -- ++(0.3,-0.3,0);
\end{tikzpicture}
\end{center}

\underline{\textbf{Câu a:}} Tam giác $ABC$ vuông cân tại $B$ với $AB = a$, $BC = a$.
Diện tích đáy:
\[
S_{\triangle ABC} = \frac12 \cdot AB \cdot BC = \frac12 \cdot a \cdot a = \frac{a^2}{2}.
\]

Chiều cao $SA$ vuông góc với đáy, $SA = a\sqrt{2}$.
Thể tích khối chóp:
\[
V_{S.ABC} = \frac13 \cdot S_{\triangle ABC} \cdot SA
            = \frac13 \cdot \frac{a^2}{2} \cdot a\sqrt{2}
            = \frac{a^3\sqrt{2}}{6}.
\]

\underline{\textbf{Câu b:}} Chọn hệ trục tọa độ $Axyz$ như sau:
$A(0;0;0)$, $B(a;0;0)$, $C(a;a;0)$, $S(0;0;a\sqrt{2})$.
(AB nằm trên trục $Ox$, hướng $AB$ dương; $BC$ song song với trục $Oy$; $AS$ nằm trên trục $Oz$.)

Tọa độ các điểm:
\[
A(0;0;0),\quad B(a;0;0),\quad C(a;a;0),\quad S(0;0;a\sqrt{2}).
\]

Vectơ pháp tuyến của mặt phẳng $(SBC)$:
\[
\overrightarrow{SB} = (a; 0; -a\sqrt{2}),\qquad
\overrightarrow{SC} = (a; a; -a\sqrt{2}).
\]
Tích có hướng:
\[
\vec{n} = \bigl[\overrightarrow{SB},\overrightarrow{SC}\bigr]
        = \begin{vmatrix}
          \mathbf{i} & \mathbf{j} & \mathbf{k}\\
          a          & 0          & -a\sqrt{2}\\
          a          & a          & -a\sqrt{2}
          \end{vmatrix}
        = (a^2\sqrt{2};\, 0;\, a^2).
\]

Diện tích tam giác $SBC$:
\[
S_{\triangle SBC} = \frac12 \bigl|\vec{n}\bigr|
                   = \frac12 \sqrt{(a^2\sqrt{2})^2 + 0 + (a^2)^2}
                   = \frac12 \sqrt{2a^4 + a^4}
                   = \frac{a^2\sqrt{3}}{2}.
\]

Khoảng cách từ $A$ đến mặt phẳng $(SBC)$ được tính qua thể tích khối chóp $A.SBC$ (cũng là khối $S.ABC$):
\[
d\bigl(A,(SBC)\bigr) = \frac{3\,V_{S.ABC}}{S_{\triangle SBC}}
                     = \frac{3\cdot \dfrac{a^3\sqrt{2}}{6}}{\dfrac{a^2\sqrt{3}}{2}}
                     = \frac{\dfrac{a^3\sqrt{2}}{2}}{\dfrac{a^2\sqrt{3}}{2}}
                     = \frac{a\sqrt{2}}{\sqrt{3}}
                     = \frac{a\sqrt{6}}{3}.
\]

Vậy thể tích khối chóp là $\displaystyle \frac{a^3\sqrt{2}}{6}$ và khoảng cách từ $A$ đến $(SBC)$ bằng $\displaystyle \frac{a\sqrt{6}}{3}$.
\end{solution}

\end{questions}

