% ===================== CÂU 1 =====================
\question[3] (Cân bằng phản ứng oxi hóa -- khử)
Xác định chất khử, chất oxi hóa và cân bằng các phản ứng sau bằng phương pháp \textbf{thăng bằng electron}:

\begin{enumerate}[label=\alph*), itemsep=8pt, leftmargin=*]
    \item $\mathrm{Fe} + \mathrm{HNO_3} \rightarrow \mathrm{Fe(NO_3)_3} + \mathrm{NO} + \mathrm{H_2O}$
    \hfill (1,5 điểm)

    \item $\mathrm{KMnO_4} + \mathrm{HCl} \rightarrow \mathrm{KCl} + \mathrm{MnCl_2} + \mathrm{Cl_2} + \mathrm{H_2O}$
    \hfill (1,5 điểm)
\end{enumerate}

\begin{solution}
\noindent \textbf{a)} \textit{Các bước cân bằng:}
\begin{itemize}[leftmargin=*, itemsep=3pt]
    \item Xác định số oxi hóa: $\overset{0}{\mathrm{Fe}} + \mathrm{H}\overset{+5}{\mathrm{N}}\mathrm{O_3} \rightarrow \overset{+3}{\mathrm{Fe}}\mathrm{(NO_3)_3} + \overset{+2}{\mathrm{N}}\mathrm{O} + \mathrm{H_2O}$
    \item Quá trình oxi hóa: $\overset{0}{\mathrm{Fe}} \rightarrow \overset{+3}{\mathrm{Fe}} + 3e^-$ \quad ($\times 1$)
    \item Quá trình khử: $\overset{+5}{\mathrm{N}} + 3e^- \rightarrow \overset{+2}{\mathrm{N}}$ \quad ($\times 1$)
    \item Hệ số: 1 Fe nhường 3e, 1 N nhận 3e $\rightarrow$ tỉ lệ $1:1$.\\
          Thêm $\mathrm{HNO_3}$ để tạo môi trường và muối: cần 3 gốc $\mathrm{NO_3^-}$ cho $\mathrm{Fe(NO_3)_3}$ và 1 cho NO $\rightarrow$ tổng 4 $\mathrm{HNO_3}$.
    \item Phương trình hoàn chỉnh:
    \[\boxed{\mathrm{Fe} + 4\mathrm{HNO_3} \longrightarrow \mathrm{Fe(NO_3)_3} + \mathrm{NO} + 2\mathrm{H_2O}}\]
    \item \textbf{Chất khử:} Fe \hspace{1cm} \textbf{Chất oxi hóa:} $\mathrm{HNO_3}$ (nguyên tử N)
\end{itemize}

\noindent \textbf{b)} \textit{Các bước cân bằng:}
\begin{itemize}[leftmargin=*, itemsep=3pt]
    \item Số oxi hóa: $\mathrm{K}\overset{+7}{\mathrm{Mn}}\mathrm{O_4} + \mathrm{H}\overset{-1}{\mathrm{Cl}} \rightarrow \mathrm{K}\overset{-1}{\mathrm{Cl}} + \overset{+2}{\mathrm{Mn}}\mathrm{Cl_2} + \overset{0}{\mathrm{Cl_2}} + \mathrm{H_2O}$
    \item Quá trình khử: $\overset{+7}{\mathrm{Mn}} + 5e^- \rightarrow \overset{+2}{\mathrm{Mn}}$ \quad ($\times 2$)
    \item Quá trình oxi hóa: $2\overset{-1}{\mathrm{Cl}} \rightarrow \overset{0}{\mathrm{Cl_2}} + 2e^-$ \quad ($\times 5$)
    \item Nhân chéo: 2 Mn nhận 10e, cần 10$\mathrm{Cl^-}$ cho 5$\mathrm{Cl_2}$.\\
          Tính lượng HCl: 2$\mathrm{KCl}$ + 2$\mathrm{MnCl_2}$ dùng 6$\mathrm{Cl^-}$, cộng với 10$\mathrm{Cl^-}$ cho $\mathrm{Cl_2}$ $\rightarrow$ tổng 16 HCl.
    \item Phương trình:
    \[\boxed{2\mathrm{KMnO_4} + 16\mathrm{HCl} \longrightarrow 2\mathrm{KCl} + 2\mathrm{MnCl_2} + 5\mathrm{Cl_2} + 8\mathrm{H_2O}}\]
    \item \textbf{Chất khử:} $\mathrm{HCl}$ (ion $\mathrm{Cl^-}$) \hspace{1cm} \textbf{Chất oxi hóa:} $\mathrm{KMnO_4}$ (ion $\mathrm{MnO_4^-}$, nguyên tử Mn)
\end{itemize}
\end{solution}

